Gebruik hierbij Binas-tabel 66F of ScienceData-tabel 11.1.3.$$, array['6aac03c6-100d-4e91-9dd1-421797ae6aa7']::uuid[]),
  ('c91c79ce-ffeb-45ad-9dda-24ebd73bd04d', '699d27b1-ac6a-438d-9703-9f3d989640ff', 15,
